#include<bits/stdc++.h>
using namespace std;
int n;
int mp[1001][1001];
bool vis[1001];
int in[1001];
bool v1[1001];
int sum;
vector<char> ans;
void dfs(int x)
{
    vis[x]=1;
    for(int i=1;i<='z';i++)
    {
        if(mp[x][i])
        {
            sum++;
            mp[x][i]=mp[i][x]=0;
            dfs(i);
        }
    }
    ans.push_back((char)x);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        char a,b;
        cin>>a>>b;
        mp[a][b]=1;
        mp[b][a]=1;
        in[a]++;
        in[b]++;
    }
    int cnt=0;
    for(int i=1;i<='z';i++)
    {
        cnt+=(in[i]%2);
    }
    if(cnt!=0&&cnt!=2)
    {
        printf("No Solution");
        return 0;
    }
    if(cnt==0)
    {
        for(int i=1;i<='z';i++)
        {
            if(in[i])
            {
                dfs(i);
                break;
            }
        }
    }
    else
    {
        for(int i=1;i<='z';i++)
        {
            if(in[i]%2==1)
            {
                dfs(i);
                break;
            }
        }
    }
    if(sum!=n)
    {
        printf("No Solution");
        return 0;
    }
    reverse(ans.begin(),ans.end());
    for(auto i:ans)
    {
        printf("%c",i);
    }
    return 0;
}
